  private final String[] boundaries={"Sponsorship transfers only limited resource capacity; it never transfers YNXT or any user asset. A fee quote is not settlement; settled status requires authoritative chain or service evidence.","资源赞助只转移受限的资源能力，绝不转移 YNXT 或任何用户资产。费用报价不等于结算；已结算状态必须有权威链上或服务证据。","資源贊助只轉移受限的資源能力，絕不轉移 YNXT 或任何使用者資產。費用報價不等於結算；已結算狀態必須有權威鏈上或服務證據。","スポンサーシップが移すのは制限されたリソース容量だけで、YNXT や利用者資産は移転しません。料金見積りは決済ではなく、決済済み表示には権威ある証拠が必要です。","후원은 제한된 리소스 용량만 이동하며 YNXT 또는 사용자 자산을 이전하지 않습니다. 수수료 견적은 결제가 아니며 완료 상태에는 권위 있는 증거가 필요합니다.","El patrocinio solo transfiere capacidad limitada; nunca transfiere YNXT ni activos. Una cotización no es liquidación; el estado liquidado exige pruebas autoritativas.","Le parrainage ne transfère qu’une capacité limitée, jamais de YNXT ni d’actif. Un devis n’est pas un règlement ; l’état réglé exige une preuve faisant autorité.","Sponsoring überträgt nur begrenzte Kapazität, niemals YNXT oder Nutzervermögen. Ein Angebot ist keine Abrechnung; abgerechnet erfordert verbindliche Nachweise.","O patrocínio transfere apenas capacidade limitada, nunca YNXT nem ativos. Uma cotação não é liquidação; o status liquidado exige evidência autoritativa.","Спонсирование передаёт только ограниченную ёмкость, но не YNXT или активы. Расчёт комиссии не является окончательным расчётом; статус требует авторитетного доказательства.","تنقل الرعاية سعة موارد محدودة فقط، ولا تنقل YNXT أو أصول المستخدم. عرض الرسوم ليس تسوية؛ وتتطلب حالة التسوية دليلاً موثوقاً.","Sponsor hanya memindahkan kapasitas terbatas, bukan YNXT atau aset. Kutipan biaya bukan penyelesaian; status selesai memerlukan bukti otoritatif."};
  private LinearLayout root;private TextView boundary,status;private EditText account,device,deviceKey,challenge,accountKey,accountSig,deviceSig,payload,idempotency;private Spinner kind;private SecureStore store;private String intentId="";
  public void onCreate(Bundle b){super.onCreate(b);store=new SecureStore(this);build();callback(getIntent());}public void onNewIntent(Intent i){super.onNewIntent(i);callback(i);}
  private EditText field(String h){EditText e=new EditText(this);e.setHint(h);e.setContentDescription(h);root.addView(e,new LinearLayout.LayoutParams(-1,-2));return e;}private Button button(String s,View.OnClickListener l){Button b=new Button(this);b.setText(s);b.setAllCaps(false);b.setOnClickListener(l);root.addView(b);return b;}private void heading(String s){TextView v=new TextView(this);v.setText(s);v.setTextSize(21);v.setTypeface(null,1);v.setPadding(0,28,0,8);root.addView(v);}
  private void build(){ScrollView sc=new ScrollView(this);root=new LinearLayout(this);root.setOrientation(LinearLayout.VERTICAL);root.setPadding(36,30,36,60);sc.addView(root);setContentView(sc);TextView title=new TextView(this);title.setText("YNX Resource Market");title.setTextSize(30);title.setTextColor(Color.rgb(0,47,167));title.setTypeface(null,1);root.addView(title);Spinner locale=new Spinner(this);locale.setAdapter(new ArrayAdapter<>(this,android.R.layout.simple_spinner_dropdown_item,names));String saved=getPreferences(0).getString("locale",Locale.getDefault().toLanguageTag());int p=0;for(int i=0;i<codes.length;i++)if(saved.startsWith(codes[i]))p=i;locale.setSelection(p);root.addView(locale);boundary=new TextView(this);boundary.setTextSize(17);boundary.setPadding(0,24,0,24);root.addView(boundary);locale.setOnItemSelectedListener(new android.widget.AdapterView.OnItemSelectedListener(){public void onNothingSelected(android.widget.AdapterView<?> p){}public void onItemSelected(android.widget.AdapterView<?> p,View v,int i,long x){getPreferences(0).edit().putString("locale",codes[i]).apply();boundary.setText(boundaries[i]);root.setLayoutDirection(codes[i].equals("ar")?View.LAYOUT_DIRECTION_RTL:View.LAYOUT_DIRECTION_LTR);}});heading("Sign in with YNX Wallet");account=field("YNX account (ynx1…)");device=field("Device ID");deviceKey=field("Ed25519 device public key");button("Create central signing challenge",v->challenge());challenge=field("Challenge ID");accountKey=field("Account public key");accountSig=field("Wallet account signature");deviceSig=field("Wallet device signature");button("Verify signed challenge",v->verify());heading("Authoritative market");button("Load resource balances",v->request("GET","/api/authority/balances/"+Uri.encode(account.getText().toString()),null));button("Load price quote",v->request("GET","/api/authority/quote",null));kind=new Spinner(this);kind.setAdapter(new ArrayAdapter<>(this,android.R.layout.simple_spinner_dropdown_item,new String[]{"rental","delegation","sponsorship"}));root.addView(kind);idempotency=field("Idempotency key");payload=field("Exact Wallet-reviewed signed payload JSON");payload.setMinLines(5);payload.setSingleLine(false);button("Submit signed purchase intent",v->intent(false));button("Retry exact failed intent",v->intent(true));status=new TextView(this);status.setPadding(0,28,0,20);status.setText("No quote, capacity or settlement result loaded.");status.setContentDescription("Resource Market status");root.addView(status);}
  private void challenge(){try{request("POST","/api/auth/challenges",new JSONObject().put("account",account.getText()).put("deviceId",device.getText()).put("deviceSigningPublicKey",deviceKey.getText()));}catch(Exception e){show(e.getMessage());}}
  private void verify(){try{request("POST","/api/auth/challenges/"+Uri.encode(challenge.getText().toString())+"/verify",new JSONObject().put("accountPublicKey",accountKey.getText()).put("accountSignature",accountSig.getText()).put("deviceSignature",deviceSig.getText()));}catch(Exception e){show(e.getMessage());}}
  private void intent(boolean retry){try{if(idempotency.getText().length()==0)idempotency.setText(UUID.randomUUID().toString());JSONObject signed=new JSONObject(payload.getText().toString());JSONObject j=new JSONObject().put("kind",kind.getSelectedItem().toString()).put("idempotencyKey",idempotency.getText()).put("payload",signed);String path=retry?"/api/authority/intents/"+Uri.encode(intentId)+"/retry":"/api/authority/intents";if(retry&&intentId.isEmpty()){show("No failed intent is available. Exact retry is required.");return;}request("POST",path,j);}catch(Exception e){show("Signed payload must be valid JSON. No transaction was submitted.");}}
  private void request(String method,String path,JSONObject body){show("Loading authoritative response…");Executors.newSingleThreadExecutor().execute(()->{try{HttpURLConnection c=(HttpURLConnection)new URL(BuildConfig.GATEWAY_BASE_URL+path).openConnection();c.setRequestMethod(method);c.setConnectTimeout(5000);c.setReadTimeout(8000);c.setRequestProperty("Content-Type","application/json");String token=store.get("session"),dev=store.get("device");if(token!=null){c.setRequestProperty("Authorization","Bearer "+token);c.setRequestProperty("X-YNX-Device-ID",dev);}if(body!=null){c.setDoOutput(true);c.getOutputStream().write(body.toString().getBytes(StandardCharsets.UTF_8));}int code=c.getResponseCode();String text=read(code<400?c.getInputStream():c.getErrorStream());if(path.contains("/verify")&&code/100==2){JSONObject s=new JSONObject(text);store.put("session",s.getString("token"));store.put("device",s.getString("deviceId"));}if(path.equals("/api/auth/challenges")&&code/100==2){JSONObject q=new JSONObject(text);runOnUiThread(()->{try{challenge.setText(q.getString("challengeId"));startActivity(new Intent(Intent.ACTION_VIEW,Uri.parse("ynxwallet://sign-app-session?callback="+Uri.encode("ynxresource://auth/callback")+"&challenge="+Uri.encode(q.getString("challengeId")))));}catch(Exception ignored){}});}if(path.contains("/intents")&&!path.contains("retry")){try{intentId=new JSONObject(text).getJSONObject("intent").getString("id");}catch(Exception ignored){}}show("HTTP "+code+"\n"+text+"\nA quote is not settlement; no asset movement is asserted.");}catch(Exception e){show("Unavailable: "+e.getMessage()+"\nNo quote, capacity, settlement or asset action was substituted.");}});}
  private String read(InputStream in)throws Exception{if(in==null)return"";ByteArrayOutputStream o=new ByteArrayOutputStream();byte[] b=new byte[2048];int n;while((n=in.read(b))>0&&o.size()<262144)o.write(b,0,n);return o.toString("UTF-8");}private int activeLocale(){String saved=getPreferences(0).getString("locale",Locale.getDefault().toLanguageTag());for(int i=0;i<codes.length;i++)if(saved.startsWith(codes[i]))return i;return 0;}private void show(String s){runOnUiThread(()->{int i=activeLocale();status.setContentDescription(statusLabels[i]);status.setText(s.startsWith("Unavailable:")?unavailable[i]+"\n"+s.substring("Unavailable:".length()).trim():s);});}
  private void callback(Intent i){if(i==null||i.getData()==null)return;Uri u=i.getData();if("ynxresource".equals(u.getScheme())){challenge.setText(Optional.ofNullable(u.getQueryParameter("challenge")).orElse(""));accountKey.setText(Optional.ofNullable(u.getQueryParameter("accountPublicKey")).orElse(""));accountSig.setText(Optional.ofNullable(u.getQueryParameter("accountSignature")).orElse(""));deviceSig.setText(Optional.ofNullable(u.getQueryParameter("deviceSignature")).orElse(""));show("Wallet proof received. Review it, then verify with the central Gateway.");}}
  static final class SecureStore{private final android.content.SharedPreferences p;SecureStore(Context c){p=c.getSharedPreferences("secure",0);}private SecretKey key()throws Exception{KeyStore k=KeyStore.getInstance("AndroidKeyStore");k.load(null);if(!k.containsAlias("ynx-resource-session")){KeyGenerator g=KeyGenerator.getInstance("AES","AndroidKeyStore");g.init(new android.security.keystore.KeyGenParameterSpec.Builder("ynx-resource-session",3).setBlockModes("GCM").setEncryptionPaddings("NoPadding").build());g.generateKey();}return((KeyStore.SecretKeyEntry)k.getEntry("ynx-resource-session",null)).getSecretKey();}void put(String n,String v)throws Exception{Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.ENCRYPT_MODE,key());byte[] out=c.doFinal(v.getBytes(StandardCharsets.UTF_8));p.edit().putString(n,Base64.getEncoder().encodeToString(c.getIV())+"."+Base64.getEncoder().encodeToString(out)).apply();}String get(String n){try{String v=p.getString(n,null);if(v==null)return null;String[] x=v.split("\\.");Cipher c=Cipher.getInstance("AES/GCM/NoPadding");c.init(Cipher.DECRYPT_MODE,key(),new GCMParameterSpec(128,Base64.getDecoder().decode(x[0])));return new String(c.doFinal(Base64.getDecoder().decode(x[1])),StandardCharsets.UTF_8);}catch(Exception e){return null;}}}
